function getTaskClassifierDecision(values) {
  const sensitive = values.data === "confidential" || values.data === "personal";
  const highRisk = values.risk === "high" || values.purpose === "decision";
  const documentUse = values.purpose === "document";

  if (sensitive && highRisk) {
    return {
      status: "Нельзя без корпоративного контура",
      tone: "danger",
      summary: "Внешний ИИ-сервис использовать нельзя: одновременно есть чувствительные данные и высокая цена ошибки.",
      actions: ["Работайте только в разрешенном корпоративном контуре.", "Если контура нет, используйте синтетический или полностью обезличенный пример.", "Окончательный вывод делает ответственный специалист."]
    };
  }

  if (sensitive) {
    return {
      status: "Только обезличенно или в разрешенном контуре",
      tone: "warning",
      summary: "Задача может быть полезной для ИИ, но данные сначала нужно убрать, заменить или обработать в утвержденной среде.",
      actions: ["Удалите ФИО, реквизиты, номера документов, контакты и внутренние идентификаторы.", "Передавайте только минимальный фрагмент, нужный для задачи.", "Проверьте результат вручную перед использованием."]
    };
  }

  if (highRisk || values.risk === "medium" || documentUse) {
    return {
      status: "Можно с ограничениями",
      tone: "caution",
      summary: "ИИ можно использовать как помощника, но результат нельзя считать готовым без проверки.",
      actions: ["Задайте роль, контекст, формат, критерии и ограничения.", "Попросите отделить факты от предположений.", "Проверьте цифры, нормы, источники и применимость результата."]
    };
  }

  return {
    status: "Можно использовать",
    tone: "safe",
    summary: "Сценарий подходит для обучения, идей, черновиков и низкорисковой работы.",
    actions: ["Не передавайте лишние данные.", "Сформулируйте ожидаемый формат ответа.", "Сохраните удачный промпт в личную библиотеку."]
  };
}

function bindTaskClassifier() {
  const root = document.getElementById("taskClassifier");
  if (!root) return;
  const result = document.getElementById("classifierResult");
  const update = () => {
    const values = {
      data: root.querySelector('[data-classifier="data"]')?.value || "public",
      risk: root.querySelector('[data-classifier="risk"]')?.value || "low",
      purpose: root.querySelector('[data-classifier="purpose"]')?.value || "draft"
    };
    const decision = getTaskClassifierDecision(values);
    result.className = `classifier-result is-${decision.tone}`;
    result.innerHTML = `
      <strong>${decision.status}</strong>
      <p>${decision.summary}</p>
      <ul>${decision.actions.map((action) => `<li>${action}</li>`).join("")}</ul>
    `;
  };
  root.querySelectorAll("[data-classifier]").forEach((field) => field.addEventListener("change", update));
  update();
}

