function renderVisualization(visual) {
  if (visual.type === "radar") {
    const count = visual.axes.length;
    const points = visual.axes.map(([, value], index) => {
      const angle = (-90 + (360 / count) * index) * Math.PI / 180;
      const radius = 44 * (value / 100);
      return `${50 + Math.cos(angle) * radius},${50 + Math.sin(angle) * radius}`;
    }).join(" ");
    return `
      <section class="section-band visual-section">
        <p class="eyebrow">Диаграмма возможностей</p>
        <h3>${visual.title}</h3>
        <div class="radar-layout">
          <svg class="radar-chart" viewBox="0 0 100 100" role="img" aria-label="${visual.title}">
            <polygon points="50,6 92,29 92,71 50,94 8,71 8,29" class="radar-grid"></polygon>
            <polygon points="50,18 78,34 78,66 50,82 22,66 22,34" class="radar-grid inner"></polygon>
            <polygon points="${points}" class="radar-area"></polygon>
            ${visual.axes.map(([, value], index) => {
              const angle = (-90 + (360 / count) * index) * Math.PI / 180;
              const x = 50 + Math.cos(angle) * 44 * (value / 100);
              const y = 50 + Math.sin(angle) * 44 * (value / 100);
              return `<circle cx="${x}" cy="${y}" r="2.2" class="radar-point"></circle>`;
            }).join("")}
          </svg>
          <div class="radar-legend">
            ${visual.axes.map(([label, value]) => `
              <div><span>${label}</span><strong>${value}/100</strong></div>
            `).join("")}
          </div>
        </div>
      </section>
    `;
  }

  if (visual.type === "flow" || visual.type === "cycle") {
    return `
      <section class="section-band visual-section">
        <p class="eyebrow">Визуальная модель</p>
        <h3>${visual.title}</h3>
        <div class="process-visual ${visual.type === "cycle" ? "is-cycle" : ""}">
          ${visual.items.map((item, index) => `
            <div class="process-step" style="--step:${index}">
              <span>${index + 1}</span>
              <strong>${item}</strong>
            </div>
          `).join("")}
        </div>
      </section>
    `;
  }

  if (visual.type === "stack") {
    return `
      <section class="section-band visual-section">
        <p class="eyebrow">Визуальная модель</p>
        <h3>${visual.title}</h3>
        <div class="stack-visual">
          ${visual.items.map((item, index) => `
            <div style="--level:${index + 1}; --step:${index}" class="stack-layer">
              <span>${index + 1}</span>
              <strong>${item}</strong>
            </div>
          `).join("")}
        </div>
      </section>
    `;
  }

  if (visual.type === "bars") {
    return `
      <section class="section-band visual-section">
        <p class="eyebrow">Визуализация</p>
        <h3>${visual.title}</h3>
        <div class="bar-visual">
          ${visual.items.map(([label, value], index) => `
            <div class="bar-row" style="--step:${index}">
              <span>${label}</span>
              <div class="bar-track"><i style="width:${value}%"></i></div>
              <strong>${value}</strong>
            </div>
          `).join("")}
        </div>
      </section>
    `;
  }

  if (visual.type === "matrix") {
    return `
      <section class="section-band visual-section">
        <p class="eyebrow">Сравнительная матрица</p>
        <h3>${visual.title}</h3>
        <div class="matrix-visual" style="grid-template-columns:minmax(130px,1.15fr) repeat(${visual.columns.length}, minmax(90px,1fr))">
          <div class="matrix-cell matrix-head">Сценарий</div>
          ${visual.columns.map((column) => `<div class="matrix-cell matrix-head">${column}</div>`).join("")}
          ${visual.rows.map((row) => row.map((cell, index) => `<div class="matrix-cell ${index === 0 ? "matrix-row-head" : ""}">${cell}</div>`).join("")).join("")}
        </div>
      </section>
    `;
  }

  if (visual.type === "quadrants") {
    return `
      <section class="section-band visual-section">
        <p class="eyebrow">Матрица решения</p>
        <h3>${visual.title}</h3>
        <div class="quadrant-wrap">
          ${visual.yAxis ? `<span class="axis-label axis-y">${visual.yAxis}</span>` : ""}
          ${visual.xAxis ? `<span class="axis-label axis-x">${visual.xAxis}</span>` : ""}
          <div class="quadrant-visual">
            ${visual.quadrants.map((item, index) => `<div class="quadrant q${index + 1}" style="--step:${index}"><strong>${item}</strong></div>`).join("")}
          </div>
        </div>
      </section>
    `;
  }

  return renderVisualizationV2(visual);
}

