function renderVisualizationV2(visual) {
  if (visual.type === "donut") {
    const total = visual.items.reduce((sum, [, value]) => sum + value, 0);
    const radius = 15.9155;
    let offset = 25;
    const segments = visual.items.map(([label, value], index) => {
      const fraction = (value / total) * 100;
      const segment = `<circle class="donut-seg seg-${index + 1}" cx="21" cy="21" r="${radius}"
        stroke-dasharray="${fraction - 1.5} ${100 - fraction + 1.5}"
        stroke-dashoffset="${offset}"></circle>`;
      offset -= fraction;
      return segment;
    }).join("");
    return `
      <section class="section-band visual-section">
        <p class="eyebrow">Структура</p>
        <h3>${visual.title}</h3>
        ${visual.note ? `<p class="visual-note">${visual.note}</p>` : ""}
        <div class="donut-layout">
          <svg class="donut-chart" viewBox="0 0 42 42" role="img" aria-label="${visual.title}">
            <circle class="donut-ring" cx="21" cy="21" r="${radius}"></circle>
            ${segments}
          </svg>
          <div class="donut-legend">
            ${visual.items.map(([label, value], index) => `
              <div class="legend-row" style="--step:${index}">
                <i class="legend-dot dot-${index + 1}"></i>
                <span>${label}</span>
                <strong>${value}%</strong>
              </div>
            `).join("")}
          </div>
        </div>
      </section>
    `;
  }

  if (visual.type === "timeline") {
    return `
      <section class="section-band visual-section">
        <p class="eyebrow">Пошаговая модель</p>
        <h3>${visual.title}</h3>
        <div class="timeline-visual">
          ${visual.items.map((item, index) => `
            <div class="timeline-step" style="--step:${index}">
              <div class="timeline-marker"><span>${index + 1}</span></div>
              <div class="timeline-card">
                <strong>${item.title}</strong>
                <p>${item.text}</p>
              </div>
            </div>
          `).join("")}
        </div>
      </section>
    `;
  }

  if (visual.type === "compare") {
    return `
      <section class="section-band visual-section">
        <p class="eyebrow">Сравнение</p>
        <h3>${visual.title}</h3>
        <div class="compare-visual">
          <div class="compare-col compare-left">
            <span class="compare-label">${visual.left.title}</span>
            <ul>${visual.left.items.map((item) => `<li>${item}</li>`).join("")}</ul>
          </div>
          <div class="compare-divider" aria-hidden="true"><span>→</span></div>
          <div class="compare-col compare-right">
            <span class="compare-label">${visual.right.title}</span>
            <ul>${visual.right.items.map((item) => `<li>${item}</li>`).join("")}</ul>
          </div>
        </div>
      </section>
    `;
  }

  if (visual.type === "checklist") {
    const checks = state.checks || {};
    return `
      <section class="section-band visual-section">
        <p class="eyebrow">Интерактивный чек-лист</p>
        <h3>${visual.title}</h3>
        ${visual.note ? `<p class="visual-note">${visual.note}</p>` : ""}
        <div class="checklist-visual" data-checklist="${visual.id}">
          ${visual.items.map((item, index) => {
            const checked = Boolean(checks[`${visual.id}:${index}`]);
            return `
              <button class="check-item ${checked ? "is-checked" : ""}" type="button" data-check="${visual.id}:${index}" style="--step:${index}">
                <span class="check-box" aria-hidden="true"></span>
                <span class="check-copy">
                  <strong>${item.text}</strong>
                  <small>${item.hint}</small>
                </span>
              </button>
            `;
          }).join("")}
        </div>
        <p class="check-progress" data-check-progress="${visual.id}"></p>
      </section>
    `;
  }

  if (visual.type === "anatomy") {
    return `
      <section class="section-band visual-section">
        <p class="eyebrow">Разбор по элементам</p>
        <h3>${visual.title}</h3>
        ${visual.note ? `<p class="visual-note">${visual.note}</p>` : ""}
        <div class="anatomy-visual">
          ${visual.segments.map((segment, index) => `
            <button class="anatomy-row seg-tone-${(index % 7) + 1}" type="button" style="--step:${index}" aria-expanded="false">
              <span class="anatomy-label">${segment.label}</span>
              <span class="anatomy-text">${segment.text}</span>
            </button>
          `).join("")}
        </div>
      </section>
    `;
  }

  return "";
}

function updateCheckProgress(checklistId) {
  const container = contentView.querySelector(`[data-checklist="${checklistId}"]`);
  const progressLabel = contentView.querySelector(`[data-check-progress="${checklistId}"]`);
  if (!container || !progressLabel) return;
  const total = container.querySelectorAll(".check-item").length;
  const done = container.querySelectorAll(".check-item.is-checked").length;
  progressLabel.textContent = done === total
    ? "Все пункты отмечены. Отличная дисциплина."
    : `Отмечено ${done} из ${total}.`;
}

function bindV2Delegation() {
  if (!contentView || contentView.dataset.v2Bound) return;
  contentView.dataset.v2Bound = "true";

  contentView.addEventListener("click", (event) => {
    const ddHead = event.target.closest(".dd-head");
    if (ddHead) {
      const item = ddHead.closest(".dd-item");
      const isOpen = item.classList.toggle("is-open");
      ddHead.setAttribute("aria-expanded", String(isOpen));
      return;
    }

    const checkItem = event.target.closest(".check-item");
    if (checkItem) {
      state.checks = state.checks || {};
      const key = checkItem.dataset.check;
      const next = !state.checks[key];
      state.checks[key] = next;
      checkItem.classList.toggle("is-checked", next);
      saveState();
      updateCheckProgress(key.split(":")[0]);
      return;
    }

    const anatomyRow = event.target.closest(".anatomy-row");
    if (anatomyRow) {
      const isOpen = anatomyRow.classList.toggle("is-open");
      anatomyRow.setAttribute("aria-expanded", String(isOpen));
    }
  });
}

async function renderGlossary() {
  if (!(await requireActiveParticipant())) return;
  currentView = "glossary";
  const categories = [...new Set(glossaryTerms.map((item) => item.cat))];

  contentView.innerHTML = `
    <section class="section-band">
      <p class="eyebrow">Справочник</p>
      <h2>Глоссарий курса</h2>
      <p>${glossaryTerms.length} ключевых терминов. Используйте поиск или фильтр по темам.</p>
      <div class="glossary-controls">
        <input id="glossarySearch" class="glossary-search" type="search" placeholder="Поиск термина...">
        <div class="glossary-chips">
          <button class="glossary-chip is-active" type="button" data-cat="all">Все</button>
          ${categories.map((cat) => `<button class="glossary-chip" type="button" data-cat="${cat}">${cat}</button>`).join("")}
        </div>
      </div>
    </section>
    <section class="glossary-grid" id="glossaryGrid">
      ${glossaryTerms.map((item, index) => `
        <article class="glossary-card" data-term="${item.term.toLowerCase()}" data-def="${escapeHtml(item.def).toLowerCase()}" data-cat="${item.cat}" style="--step:${index % 8}">
          <span class="glossary-cat">${item.cat}</span>
          <h3>${item.term}</h3>
          <p>${item.def}</p>
        </article>
      `).join("")}
    </section>
  `;

  const grid = document.getElementById("glossaryGrid");
  const search = document.getElementById("glossarySearch");
  let activeCat = "all";

  const applyFilter = () => {
    const query = search.value.trim().toLowerCase();
    let visible = 0;
    grid.querySelectorAll(".glossary-card").forEach((card) => {
      const matchesCat = activeCat === "all" || card.dataset.cat === activeCat;
      const matchesQuery = !query || card.dataset.term.includes(query) || card.dataset.def.includes(query);
      const show = matchesCat && matchesQuery;
      card.classList.toggle("is-hidden", !show);
      if (show) visible += 1;
    });
  };

  search.addEventListener("input", applyFilter);
  contentView.querySelectorAll(".glossary-chip").forEach((chip) => {
    chip.addEventListener("click", () => {
      activeCat = chip.dataset.cat;
      contentView.querySelectorAll(".glossary-chip").forEach((item) => item.classList.toggle("is-active", item === chip));
      applyFilter();
    });
  });

  renderNav();
  renderObjectives();
  renderRoadmap();
  prepareAnimations(contentView);
  window.scrollTo({ top: 0, behavior: "smooth" });
}

function renderQuestion(moduleId, question, questionIndex, moduleState) {
  const selected = moduleState.answers?.[questionIndex];
  return `
    <div class="question mcq" data-question="${questionIndex}">
      <p>${questionIndex + 1}. ${question.q}</p>
      <div class="choices">
        ${question.options.map((option, optionIndex) => {
          const isSelected = Number(selected) === optionIndex;
          const resultClass = moduleState.submitted
            ? optionIndex === question.answer ? "is-correct" : isSelected ? "is-wrong" : ""
            : isSelected ? "is-selected" : "";
          return `<button class="choice-button ${resultClass}" type="button" data-module-id="${moduleId}" data-question-index="${questionIndex}" data-option-index="${optionIndex}">${option}</button>`;
        }).join("")}
      </div>
      ${moduleState.submitted ? `<div class="explanation">${question.why}</div>` : ""}
    </div>
  `;
}

function bindQuestionEvents(moduleId) {
  contentView.querySelectorAll(`[data-module-id="${moduleId}"]`).forEach((button) => {
    button.addEventListener("click", () => {
      const moduleState = state.modules[moduleId] || { answers: {}, submitted: false };
      if (moduleState.submitted) return;
      const questionIndex = button.dataset.questionIndex;
      moduleState.answers[questionIndex] = Number(button.dataset.optionIndex);
      state.modules[moduleId] = moduleState;
      saveState();
      contentView
        .querySelectorAll(`[data-module-id="${moduleId}"][data-question-index="${questionIndex}"]`)
        .forEach((choice) => choice.classList.toggle("is-selected", choice === button));
      button.classList.remove("is-pulsing");
      void button.offsetWidth;
      button.classList.add("is-pulsing");
    });
  });
}

async function submitModule(module) {
  if (!(await requireActiveParticipant())) return;
  const moduleState = state.modules[module.id] || { answers: {}, submitted: false };
  const answered = Object.keys(moduleState.answers).length;
  if (answered < module.quiz.length) {
    showToast("Ответьте на все вопросы мини-теста.");
    return;
  }

  moduleState.submitted = true;
  moduleState.score = module.quiz.reduce((sum, question, index) => {
    return sum + (Number(moduleState.answers[index]) === question.answer ? 1 : 0);
  }, 0);
  state.modules[module.id] = moduleState;
  saveState();
  renderModule(currentModuleIndex, { scrollMode: "result" });
  updateProgress();
  void syncModuleResult(module);
}

function renderModuleResult(module, moduleState) {
  const percent = Math.round((moduleState.score / module.quiz.length) * 100);
  const text = percent === 100
    ? "Отлично. Можно двигаться дальше и применять прием на практике."
    : "Повторите пояснения к ошибочным вопросам и попробуйте применить блок на своей задаче.";
  const syncStatus = state.moduleSync?.[module.id] || "не отправлено";
  return `
    <div class="result-panel">
      <div class="result-score">${percent}%</div>
      <strong>${moduleState.score} из ${module.quiz.length} правильных ответов</strong>
      <p>${text}</p>
      <p><strong>Синхронизация в таблицу:</strong> ${syncStatus}</p>
    </div>
  `;
}

async function syncModuleResult(module) {
  if (!RESULTS_ENDPOINT || !validateParticipant({ quiet: true })) return;
  const moduleState = state.modules[module.id];
  if (!moduleState?.submitted) return;

  const percent = Math.round((moduleState.score / module.quiz.length) * 100);
  state.moduleSync[module.id] = "отправляется";
  saveState();
  renderResultsOverview();
  if (currentView === "module" && modules[currentModuleIndex]?.id === module.id) {
    const resultNode = document.getElementById("moduleResult");
    if (resultNode) resultNode.innerHTML = renderModuleResult(module, moduleState);
  }

  try {
    await requestServerAction("submitModuleResult", {
      name: state.participant.name,
      department: state.participant.department || "",
      passwordHash: state.participant.passwordHash,
      submittedAt: new Date().toISOString(),
      build: COURSE_BUILD,
      moduleId: module.id,
      moduleTitle: module.title,
      correct: moduleState.score,
      total: module.quiz.length,
      percent
    }, { timeout: 20000 });

    state.moduleSync[module.id] = "отправлено";
    saveState();
    renderResultsOverview();
    if (currentView === "module" && modules[currentModuleIndex]?.id === module.id) {
      const resultNode = document.getElementById("moduleResult");
      if (resultNode) resultNode.innerHTML = renderModuleResult(module, moduleState);
    }
  } catch (error) {
    state.moduleSync[module.id] = explainEndpointError(error);
    saveState();
    renderResultsOverview();
    if (currentView === "module" && modules[currentModuleIndex]?.id === module.id) {
      const resultNode = document.getElementById("moduleResult");
      if (resultNode) resultNode.innerHTML = renderModuleResult(module, moduleState);
    }
    showToast("Мини-тест сохранён локально, но не отправлен в таблицу.");
  }
}

// Карточка промпта (используется в библиотеке и в блоке департамента).
function promptCardHtml(p, i, chipLabel, hideTag) {
  const saved = getExperienceState().savedPrompts.includes(String(i));
  const note = getExperienceState().promptNotes[String(i)] || "";
  return `
    <article class="prompt-card ${p.gold ? "is-gold" : ""}">
      <div>
        <p class="eyebrow">${escapeHtml(p.use)}</p>
        <h3>${escapeHtml(p.title)}</h3>
        ${!hideTag && p.dept && p.dept !== "universal" ? `<span class="lib-tag">${escapeHtml(chipLabel ? chipLabel(p.dept) : p.dept)}</span>` : ""}
      </div>
      <pre id="prompt-${i}">${escapeHtml(p.text)}</pre>
      ${p.note ? `<p class="lib-privacy">⚠️ В этом промпте возможны персональные или служебные данные. Обезличьте их сами перед отправкой в ИИ.</p>` : ""}
      <div class="prompt-card-actions">
        <button class="copy-button" type="button" data-copy="${i}">Скопировать</button>
        <button class="save-prompt-button ${saved ? "is-saved" : ""}" type="button" data-save-prompt="${i}">${saved ? "В моей подборке" : "Сохранить"}</button>
      </div>
      ${saved ? `<label class="prompt-note"><span>Моя заметка</span><textarea data-prompt-note="${i}" placeholder="Где применили и что стоит уточнить">${escapeHtml(note)}</textarea></label>` : ""}
    </article>`;
}

function bindPromptCopy(root) {
  (root || contentView).querySelectorAll("[data-copy]").forEach((button) => {
    button.addEventListener("click", async () => {
      const prompt = promptLibrary[Number(button.dataset.copy)].text;
      try {
        if (navigator.clipboard?.writeText) { await navigator.clipboard.writeText(prompt); }
        else { copyWithFallback(prompt); }
        showToast("Промпт скопирован.");
      } catch {
        try { copyWithFallback(prompt); showToast("Промпт скопирован."); }
        catch { showToast("Не удалось скопировать автоматически. Выделите текст вручную."); }
      }
    });
  });
}

function bindPromptCollection(root) {
  (root || contentView).querySelectorAll("[data-save-prompt]").forEach((button) => {
    button.addEventListener("click", () => {
      const next = window.CourseExperienceCore.toggleSavedPrompt(getExperienceState(), button.dataset.savePrompt);
      updateExperience(next);
      showToast(next.savedPrompts.includes(button.dataset.savePrompt) ? "Промпт добавлен в вашу подборку." : "Промпт убран из вашей подборки.");
      renderLibrary({ keepScroll: true });
    });
  });
  (root || contentView).querySelectorAll("[data-prompt-note]").forEach((field) => {
    field.addEventListener("input", () => {
      const next = getExperienceState();
      next.promptNotes[field.dataset.promptNote] = field.value;
      updateExperience(next);
    });
  });
}

async function renderLibrary(options = {}) {
  if (!(await requireActiveParticipant())) return;
  currentView = "library";
  const myDept = departmentIdFor(state.participant?.department);
  const order = ["universal", ...DEPARTMENTS.map((d) => d.id)];
  const present = [];
  promptLibrary.forEach((p) => { const d = p.dept || "universal"; if (!present.includes(d)) present.push(d); });
  present.sort((a, b) => order.indexOf(a) - order.indexOf(b));
  const savedIds = new Set(getExperienceState().savedPrompts);
  const filter = (libraryFilter === "all" || libraryFilter === "saved" || present.includes(libraryFilter)) ? libraryFilter : "all";
  const chipLabel = (id) => id === "universal" ? "Универсальные" : (DEPARTMENTS.find((d) => d.id === id)?.name || id);
  const visible = promptLibrary.map((p, i) => ({ p, i })).filter(({ p, i }) => filter === "all" || (filter === "saved" ? savedIds.has(String(i)) : (p.dept || "universal") === filter));
  // Сортировка: по департаменту (порядок выше), затем по популярности (pop), затем по позиции.
  visible.sort((a, b) => {
    const da = order.indexOf(a.p.dept || "universal"), db = order.indexOf(b.p.dept || "universal");
    if (da !== db) return da - db;
    const pa = a.p.pop == null ? 50 : a.p.pop, pb = b.p.pop == null ? 50 : b.p.pop;
    return pa !== pb ? pa - pb : a.i - b.i;
  });
  const showChips = present.length > 1; // фильтр нужен, только когда появятся департаментские промпты

  contentView.innerHTML = `
    <section class="section-band">
      <p class="eyebrow">Рабочий набор</p>
      <h2>Библиотека готовых промптов</h2>
      <p>Замените поля в квадратных скобках на свои данные. Перед отправкой удалите персональную и конфиденциальную информацию. Все промпты доступны всем — фильтр лишь помогает найти нужное.</p>
      ${showChips ? `<div class="lib-filter">
        <button class="lib-chip ${filter === "all" ? "is-active" : ""}" type="button" data-lib-filter="all">Все</button>
        <button class="lib-chip ${filter === "saved" ? "is-active" : ""}" type="button" data-lib-filter="saved">Моя подборка (${savedIds.size})</button>
        ${present.map((id) => `<button class="lib-chip ${filter === id ? "is-active" : ""} ${id === myDept ? "is-mine" : ""}" type="button" data-lib-filter="${id}">${escapeHtml(chipLabel(id))}${id === myDept ? " ★" : ""}</button>`).join("")}
      </div>` : ""}
    </section>
    <section id="promptLibraryBook" class="prompt-library-book" aria-label="Вход в библиотеку промптов"></section>
    <section class="prompt-grid">
      ${visible.map(({ p, i }) => promptCardHtml(p, i, chipLabel)).join("")}
    </section>
  `;

  contentView.querySelectorAll("[data-lib-filter]").forEach((button) => {
    button.addEventListener("click", () => { libraryFilter = button.dataset.libFilter; renderLibrary({ keepScroll: true }); });
  });

  bindPromptCopy(contentView);
  bindPromptCollection(contentView);
  window.CourseExperience?.enhancePromptLibrary();

  renderNav();
  renderObjectives();
  renderRoadmap();
  prepareAnimations(contentView);
  // При смене фильтра не прокручиваем наверх — остаёмся на месте.
  if (!options.keepScroll) window.scrollTo({ top: 0, behavior: "smooth" });
}

// Категория для вопросов из банка мини-тестов (для разбивки по темам в итоге).
const MODULE_CATEGORY = {
  intro: "basics", tools: "tools", risks: "verification", qwen: "tools", deepseek: "tools", yandexgpt: "tools", gigachat: "tools", "task-guard": "security",
  prompt: "prompt", formula: "prompt", "simple-complex": "prompt", iterations: "prompt",
  mistakes: "prompt", library: "prompt", verification: "verification", docs: "docs",
  security: "security", multimodal: "tools", tables: "verification", longdocs: "docs",
  comms: "prompt", boundary: "security", "final-practice": "basics"
};

function shuffleArray(arr) {
  const a = arr.slice();
  for (let i = a.length - 1; i > 0; i -= 1) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// Пул вопросов = итоговые + банк мини-тестов (с проставленной категорией).
function buildFinalPool() {
  const pool = finalQuestions.map((q) => ({ q: q.q, options: q.options, answer: q.answer, category: q.category }));
  modules.forEach((module) => {
    const category = MODULE_CATEGORY[module.id] || module.category || "basics";
    (module.quiz || []).forEach((item) => {
      if (item && Array.isArray(item.options)) {
        pool.push({ q: item.q, options: item.options, answer: item.answer, category });
      }
    });
  });
  return pool;
}

const FINAL_TEST_SIZE = 30;

// Собирает попытку: случайная выборка из пула + перемешанные варианты.
function buildFinalAttempt(size) {
  const pool = shuffleArray(buildFinalPool());
  const picked = pool.slice(0, Math.min(size, pool.length));
  return picked.map((question, index) => {
    const order = shuffleArray(question.options.map((opt, i) => ({ opt, i })));
    const options = order.map((o) => o.opt);
    const answer = order.findIndex((o) => o.i === question.answer);
    return { id: `final-${index}`, q: question.q, options, answer, category: question.category };
  });
}

// Текущая попытка участника (стабильна до сброса/новой попытки).
function getFinalSet() {
  if (Array.isArray(state.finalAttempt) && state.finalAttempt.length) return state.finalAttempt;
  state.finalAttempt = buildFinalAttempt(FINAL_TEST_SIZE);
  if (!state.finalSubmitted) state.finalAnswers = {};
  saveState();
  return state.finalAttempt;
}

async function renderFinalTest(options = {}) {
  if (!(await requireActiveParticipant())) return;
  const scrollMode = options.scrollMode || "top";
  currentView = "final";
  const finalSubmitted = state.finalSubmitted;
  const finalSet = getFinalSet();

  contentView.innerHTML = `
    <section class="section-band">
      <p class="eyebrow">Итоговая диагностика</p>
      <h2>Финальный тест и рекомендации</h2>
      <p>Ответьте на вопросы. После проверки курс покажет уровень подготовки и рекомендации по слабым зонам. Вопросы и варианты у каждой попытки в случайном порядке.</p>
    </section>
    <section class="section-band quiz-card">
      ${finalSet.map((question, index) => renderFinalQuestion(question, index, finalSubmitted)).join("")}
      <div class="lesson-actions">
        <button class="primary-button" type="button" id="submitFinal">Проверить результат</button>
        <button class="secondary-button" type="button" id="goLibrary">Открыть библиотеку промптов</button>
      </div>
      <div id="finalResult">${finalSubmitted ? renderFinalResult() : ""}</div>
    </section>
  `;

  contentView.querySelectorAll("[data-final-question]").forEach((button) => {
    button.addEventListener("click", () => {
      if (state.finalSubmitted) return;
      const questionIndex = button.dataset.finalQuestion;
      state.finalAnswers[questionIndex] = Number(button.dataset.finalOption);
      saveState();
      contentView
        .querySelectorAll(`[data-final-question="${questionIndex}"]`)
        .forEach((choice) => choice.classList.toggle("is-selected", choice === button));
      button.classList.remove("is-pulsing");
      void button.offsetWidth;
      button.classList.add("is-pulsing");
    });
  });

  document.getElementById("submitFinal").addEventListener("click", submitFinal);
  document.getElementById("goLibrary").addEventListener("click", renderLibrary);
  const sendButton = document.getElementById("sendResultsButton");
  if (sendButton) sendButton.addEventListener("click", submitResults);
  const downloadButton = document.getElementById("downloadResultsButton");
  if (downloadButton) downloadButton.addEventListener("click", downloadResultsJson);

  renderNav();
  renderObjectives();
  renderRoadmap();
  updateProgress();
  prepareAnimations(contentView);
  // Показываем тест сразу: длинный список вопросов не должен зависеть от
  // появления по скроллу, иначе он выглядит «пустым», пока не доскроллишь.
  contentView.querySelectorAll(".revealable").forEach((el) => el.classList.add("is-revealed"));
  if (scrollMode === "result") {
    document.getElementById("finalResult")?.scrollIntoView({ behavior: "smooth", block: "start" });
  } else if (scrollMode === "top") {
    // Прокручиваем к самому тесту, а не к началу страницы (иначе видно только герой-блок).
    contentView.scrollIntoView({ behavior: "smooth", block: "start" });
  }
}

function renderFinalQuestion(question, index, submitted) {
  const selected = state.finalAnswers[index];
  return `
    <div class="question mcq">
      <p>${index + 1}. ${question.q}</p>
      <div class="choices">
        ${question.options.map((option, optionIndex) => {
          const isSelected = Number(selected) === optionIndex;
          const resultClass = submitted
            ? optionIndex === question.answer ? "is-correct" : isSelected ? "is-wrong" : ""
            : isSelected ? "is-selected" : "";
          return `<button class="choice-button ${resultClass}" type="button" data-final-question="${index}" data-final-option="${optionIndex}">${option}</button>`;
        }).join("")}
      </div>
    </div>
  `;
}

async function submitFinal() {
  if (!(await requireActiveParticipant())) return;
  if (Object.keys(state.finalAnswers).length < getFinalSet().length) {
    showToast("Ответьте на все вопросы итогового теста.");
    return;
  }
  state.finalSubmitted = true;
  saveState();
  renderFinalTest({ scrollMode: "result" });
  updateProgress();
  // Авто-выгрузка в таблицу сразу по «проверить результат» (без отдельной кнопки).
  // Ответы после сдачи не меняются, поэтому шлём один раз: если уже отправляется/
  // отправлено — повторно не дёргаем (статус «не отправлено» начинается с «не»);
  // при ошибке пользователь может нажать «Отправить ещё раз».
  if (!/^отправ/i.test(state.resultStatus || "")) {
    void submitResults();
  }
}

function renderFinalResult() {
  const finalSet = getFinalSet();
  const correct = finalSet.reduce((sum, question, index) => {
    return sum + (Number(state.finalAnswers[index]) === question.answer ? 1 : 0);
  }, 0);
  const percent = Math.round((correct / finalSet.length) * 100);
  const level = getLevel(percent);
  const recommendations = getRecommendations(percent);
  const categoryLabels = { prompt: "Промпты", security: "Безопасность", tools: "Инструменты", verification: "Проверка", docs: "Документы", basics: "Основы" };
  const categoryScores = finalSet.reduce((acc, question, index) => {
    if (!acc[question.category]) acc[question.category] = { correct: 0, total: 0 };
    acc[question.category].total += 1;
    if (Number(state.finalAnswers[index]) === question.answer) acc[question.category].correct += 1;
    return acc;
  }, {});

  return `
    <div class="result-panel">
      <div class="result-score">${percent}%</div>
      <strong>${level}</strong>
      <p>${correct} из ${finalSet.length} правильных ответов.</p>
      <div class="final-categories">
        ${Object.entries(categoryScores).map(([category, score], index) => {
          const categoryPercent = Math.round((score.correct / score.total) * 100);
          return `
            <div class="final-cat-row" style="--step:${index}">
              <span>${categoryLabels[category] || category}</span>
              <div class="final-cat-track"><i class="${categoryPercent < 50 ? "is-low" : categoryPercent < 80 ? "is-mid" : "is-high"}" style="width:${categoryPercent}%"></i></div>
              <strong>${score.correct}/${score.total}</strong>
            </div>
          `;
        }).join("")}
      </div>
      <ul class="recommendations">
        ${recommendations.map((item) => `<li>${item}</li>`).join("")}
      </ul>
      ${renderMistakeInsights(finalSet)}
      <div class="submit-results-box">
        <p><strong>Статус отправки:</strong> ${state.resultStatus || "не отправлено"}</p>
        <p class="submit-hint">Результат выгружается в таблицу автоматически. Если статус с ошибкой — нажмите «Отправить ещё раз».</p>
        <div class="lesson-actions">
          <button class="secondary-button" type="button" id="sendResultsButton">Отправить ещё раз</button>
          <button class="secondary-button" type="button" id="downloadResultsButton">Скачать файл</button>
        </div>
        ${!RESULTS_ENDPOINT ? `<p class="submit-hint">Ссылка Google Apps Script пока не указана. Скачайте файл результата или вставьте ссылку в константу RESULTS_ENDPOINT.</p>` : ""}
      </div>
    </div>
  `;
}

function getLevel(percent) {
  if (percent < 50) return "Начальный уровень. Нужно повторить основы промптов и безопасность.";
  if (percent < 75) return "Базовый пользователь. Можно применять ИИ в простых рабочих задачах.";
  if (percent < 90) return "Уверенный пользователь. Можно переходить к сложным промптам и работе с документами.";
  return "Продвинутый старт. Можно помогать коллегам и собирать библиотеку промптов.";
}

function getRecommendations(percent) {
  const wrongCategories = getFinalSet().reduce((acc, question, index) => {
    if (Number(state.finalAnswers[index]) !== question.answer) {
      acc[question.category] = (acc[question.category] || 0) + 1;
    }
    return acc;
  }, {});

  const recommendations = [];
  if (wrongCategories.prompt) recommendations.push("Ошибки в промптах: повторите блоки про промпт, формулу запроса, сложность задач и итерации.");
  if (wrongCategories.security) recommendations.push("Ошибки в безопасности: повторите блок безопасности и карту допуска задач.");
  if (wrongCategories.tools) recommendations.push("Ошибки в выборе нейросетей: повторите блок анализа инструментов и блоки Qwen, DeepSeek, YandexGPT и GigaChat.");
  if (wrongCategories.verification) recommendations.push("Ошибки в проверке результата: повторите блок проверки ответа и используйте промпт самопроверки.");
  if (wrongCategories.docs) recommendations.push("Ошибки в работе с документами: повторите блок документов и шаблоны проверки текста.");
  if (percent < 50) recommendations.push("Общий результат низкий: пройдите курс заново и разберите открытые вопросы после каждого блока.");
  if (percent >= 90) recommendations.push("Высокий результат: создайте личную библиотеку промптов для своих регулярных задач.");

  return recommendations.length ? recommendations : ["Результат ровный. Закрепите навык на реальной рабочей задаче и сохраните удачный промпт."];
}

function renderMistakeInsights(finalSet) {
  const wrongCategories = finalSet.reduce((acc, question, index) => {
    if (Number(state.finalAnswers[index]) !== question.answer) {
      acc[question.category] = (acc[question.category] || 0) + 1;
    }
    return acc;
  }, {});
  const totalWrong = Object.values(wrongCategories).reduce((sum, count) => sum + count, 0);
  const personalInsights = window.CourseExperienceCore.buildErrorInsights(finalSet, state.finalAnswers);
  const cards = [
    {
      title: "Промпт без контекста",
      active: Boolean(wrongCategories.prompt || wrongCategories.basics),
      action: "Добавляйте цель, аудиторию, исходные условия, ограничения и ожидаемый формат результата."
    },
    {
      title: "Нет критериев проверки",
      active: Boolean(wrongCategories.prompt || wrongCategories.verification),
      action: "До отправки запроса задавайте критерии: что считать хорошим ответом, что проверить и чего не делать."
    },
    {
      title: "Слишком много доверия цифрам",
      active: Boolean(wrongCategories.verification || wrongCategories.docs),
      action: "Все расчеты, даты, суммы, проценты и ссылки сверяйте с исходной таблицей или первоисточником."
    },
    {
      title: "Загрузка чувствительных данных",
      active: Boolean(wrongCategories.security),
      action: "Используйте минимум данных, условные обозначения, учебный пример или разрешенный корпоративный контур."
    },
    {
      title: "Итоговый вывод без источников",
      active: Boolean(wrongCategories.verification || wrongCategories.security || wrongCategories.docs),
      action: "Разделяйте факты, предположения и выводы. Для важных утверждений указывайте источник проверки."
    }
  ];

  return `
    <section class="mistake-insights">
      <div class="section-title-row">
        <div>
          <p class="eyebrow">Разбор типовых ошибок</p>
          <h3>Где чаще всего ошибаются участники</h3>
        </div>
        <span class="tag">${totalWrong ? `${totalWrong} зон сигнала` : "критичных сигналов нет"}</span>
      </div>
      ${personalInsights.length ? `<div class="personal-insight-grid">
        ${personalInsights.map((item) => `<article class="personal-insight-card">
          <span>${item.count} ${item.count === 1 ? "вопрос" : "вопроса"}</span>
          <h4>${item.title}</h4>
          <p>${item.action}</p>
        </article>`).join("")}
      </div>` : `<p class="field-status">По итоговому тесту нет выраженных слабых зон. Закрепите навык на одной рабочей задаче.</p>`}
      <div class="mistake-grid">
        ${cards.map((card, index) => `
          <article class="mistake-card ${card.active ? "is-active" : "is-ok"}" style="--step:${index}">
            <span>${card.active ? "Повторить" : "Под контролем"}</span>
            <h4>${card.title}</h4>
            <p>${card.action}</p>
          </article>
        `).join("")}
      </div>
    </section>
  `;
}

function getOpenAnswerRows() {
  const courseRows = modules.flatMap((module) => (module.openQuestions || [])
    .map((question, index) => {
      const key = `${module.id}:${index}`;
      return {
        moduleId: module.id,
        moduleTitle: module.title,
        question,
        answer: state.openAnswers?.[key] || ""
      };
    }));

  const departmentBlock = getDepartmentBlock();
  const departmentRows = departmentBlock ? (departmentBlock.cases || []).map((question, index) => {
    const key = `${departmentBlock.id}:${index}`;
    return {
      moduleId: departmentBlock.id,
      moduleTitle: departmentBlock.title,
      question,
      answer: state.openAnswers?.[key] || ""
    };
  }) : [];

  return [...courseRows, ...departmentRows].filter((row) => String(row.answer || "").trim());
}

function getPracticeAnswerRows() {
  return modules
    .map((module) => ({
      moduleId: module.id,
      moduleTitle: module.title,
      task: module.practice || "",
      answer: state.practice?.[module.id] || ""
    }))
    .filter((row) => row.task && String(row.answer || "").trim());
}

function buildResultsPayload() {
  const finalSet = getFinalSet();
  const correct = finalSet.reduce((sum, question, index) => {
    return sum + (Number(state.finalAnswers[index]) === question.answer ? 1 : 0);
  }, 0);
  const percent = Math.round((correct / finalSet.length) * 100);
  const categoryScores = finalSet.reduce((acc, question, index) => {
    if (!acc[question.category]) acc[question.category] = { correct: 0, total: 0 };
    acc[question.category].total += 1;
    if (Number(state.finalAnswers[index]) === question.answer) acc[question.category].correct += 1;
    return acc;
  }, {});
  const completedModules = modules
    .filter((module) => state.modules[module.id]?.submitted)
    .map((module) => ({ id: module.id, title: module.title }));
  const openAnswerRows = getOpenAnswerRows();
  const practiceAnswerRows = getPracticeAnswerRows();

  return {
    action: "submitResult",
    submittedAt: new Date().toISOString(),
    build: COURSE_BUILD,
    participant: state.participant,
    score: { correct, total: finalSet.length, percent, level: getLevel(percent) },
    categoryScores,
    completedModules,
    finalAnswers: finalSet.map((question, index) => ({
      question: question.q,
      selected: question.options[state.finalAnswers[index]],
      correct: question.options[question.answer],
      isCorrect: Number(state.finalAnswers[index]) === question.answer,
      category: question.category
    })),
    openAnswers: state.openAnswers,
    openAnswerRows,
    practiceAnswers: state.practice,
    practiceAnswerRows
  };
}

function validateParticipant(options = {}) {
  const quiet = Boolean(options.quiet);
  const name = state.participant?.name?.trim();
  const department = state.participant?.department?.trim();
  if (!state.participant?.authenticated || !state.participant?.passwordHash) {
    if (!quiet) {
      showToast("Войдите или зарегистрируйтесь перед отправкой результата.");
      renderParticipantForm();
      participantView.scrollIntoView({ behavior: "smooth", block: "center" });
    }
    return false;
  }
  if (!name || !department) {
    if (!quiet) {
      showToast("В учетной записи не хватает ФИО или подразделения.");
      renderParticipantForm();
      participantView.scrollIntoView({ behavior: "smooth", block: "center" });
    }
    return false;
  }
  return true;
}

function explainEndpointError(error) {
  const message = String(error?.message || error || "");
  if (/Неизвестное действие|старой версии/i.test(message)) return "ошибка: Apps Script опубликован в старой версии";
  if (/отключ|заблок|удал|blocked|deleted|disabled/i.test(message)) return "доступ отключён владельцем";
  if (/timeout|request failed|auth request failed/i.test(message)) return "ошибка связи с Google Apps Script";
  if (/не найден|зарегистрируйтесь/i.test(message)) return "пользователь не найден в таблице";
  if (/парол/i.test(message)) return "ошибка пароля";
  return `ошибка: ${message || "не удалось отправить"}`;
}

function getParticipantRequestData() {
  return {
    name: state.participant.name,
    department: state.participant.department || "",
    passwordHash: state.participant.passwordHash
  };
}

function buildFinalSummaryRequest(payload) {
  return {
    ...getParticipantRequestData(),
    submittedAt: payload.submittedAt,
    build: payload.build || COURSE_BUILD,
    percent: payload.score.percent,
    correct: payload.score.correct,
    total: payload.score.total,
    level: payload.score.level,
    categoryScores: JSON.stringify(payload.categoryScores || {}),
    completedModules: JSON.stringify(payload.completedModules || []),
    finalAnswerIndexes: getFinalSet().map((question, index) => Number(state.finalAnswers[index] ?? -1)).join(",")
  };
}

function chunkArray(items, size) {
  const chunks = [];
  for (let i = 0; i < items.length; i += size) chunks.push(items.slice(i, i + size));
  return chunks;
}

async function ensureResultsEndpointReady() {
  const health = await requestServerAction("health", {}, { timeout: 20000 });
  const capabilities = health?.capabilities || {};
  if (!capabilities.submitOpenAnswers || !capabilities.submitPracticeAnswers) {
    throw new Error("Apps Script опубликован в старой версии: нет пакетной отправки открытых и практических ответов");
  }
  return health;
}

async function sendRowsInChunks(action, rows, fieldName, baseData, chunkSize = 3) {
  if (!rows.length) return 0;
  let saved = 0;
  for (const chunk of chunkArray(rows, chunkSize)) {
    const response = await requestServerAction(action, {
      ...baseData,
      [fieldName]: JSON.stringify(chunk)
    }, { timeout: 25000 });
    saved += Number(response?.saved ?? chunk.length);
  }
  if (saved !== rows.length) {
    throw new Error(`${action}: сохранено ${saved} из ${rows.length}`);
  }
  return saved;
}

async function sendFinalResultsViaGet(payload) {
  await ensureResultsEndpointReady();
  await requestServerAction("submitFinalSummary", buildFinalSummaryRequest(payload), { timeout: 20000 });

  // Развёрнутые ответы итогового теста — пачками по 5, чтобы не упереться в длину URL.
  const finalRows = (payload.finalAnswers || []).map((answer, index) => ({
    number: index + 1,
    category: answer.category,
    question: answer.question,
    selected: answer.selected,
    correct: answer.correct,
    isCorrect: answer.isCorrect
  }));
  for (const chunk of chunkArray(finalRows, 5)) {
    await requestServerAction("submitFinalAnswers", {
      ...getParticipantRequestData(),
      submittedAt: payload.submittedAt,
      build: payload.build || COURSE_BUILD,
      answers: JSON.stringify(chunk)
    }, { timeout: 20000 });
  }

  const baseData = {
    ...getParticipantRequestData(),
    submittedAt: payload.submittedAt,
    build: payload.build || COURSE_BUILD
  };

  await sendRowsInChunks("submitOpenAnswers", payload.openAnswerRows || [], "rows", baseData, 3);
  await sendRowsInChunks("submitPracticeAnswers", payload.practiceAnswerRows || [], "rows", baseData, 3);
}

async function sendResultsViaLegacyPost(payload) {
  const body = JSON.stringify(payload);

  if (navigator.sendBeacon) {
    const blob = new Blob([body], { type: "text/plain;charset=UTF-8" });
    const queued = navigator.sendBeacon(RESULTS_ENDPOINT, blob);
    if (queued) return;
  }

  await fetch(RESULTS_ENDPOINT, {
    method: "POST",
    mode: "no-cors",
    cache: "no-store",
    headers: { "Content-Type": "text/plain;charset=UTF-8" },
    body,
    keepalive: true
  });
}

async function submitResults() {
  if (!state.finalSubmitted) {
    showToast("Сначала пройдите итоговый тест.");
    return;
  }
  if (!(await requireActiveParticipant())) return;
  if (!validateParticipant()) return;
  const payload = buildResultsPayload();

  if (!RESULTS_ENDPOINT) {
    state.resultStatus = "ошибка: не указана ссылка Google Apps Script";
    saveState();
    renderFinalTest({ scrollMode: "keep" });
    showToast("Ссылка отправки не указана. Скачайте файл результата или настройте Google Apps Script.");
    return;
  }

  state.resultStatus = "отправляется";
  saveState();
  renderResultsOverview();
  renderFinalTest({ scrollMode: "keep" });

  try {
    await sendFinalResultsViaGet(payload);
    state.resultStatus = "отправлено";
    saveState();
    renderResultsOverview();
    renderFinalTest({ scrollMode: "keep" });
    showToast("Результат отправлен в таблицу.");
  } catch (error) {
    if (/Неизвестное действие/i.test(String(error?.message || error))) {
      state.resultStatus = explainEndpointError(error);
      saveState();
      renderResultsOverview();
      renderFinalTest({ scrollMode: "keep" });
      showToast("Apps Script опубликован в старой версии. Обновите веб-приложение Google.");
      return;
    }

    state.resultStatus = explainEndpointError(error);
    saveState();
    renderResultsOverview();
    renderFinalTest({ scrollMode: "keep" });
    showToast("Не удалось отправить результат. Проверьте публикацию Google Apps Script или скачайте файл результата.");
  }
}

function downloadResultsJson() {
  if (!state.finalSubmitted) {
    showToast("Сначала пройдите итоговый тест.");
    return;
  }
  const blob = new Blob([JSON.stringify(buildResultsPayload(), null, 2)], { type: "application/json" });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = `ai-course-result-${Date.now()}.json`;
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
}

function updateProgress() {
  const completedModules = modules.filter((module) => state.modules[module.id]?.submitted).length;
  const finalBonus = state.finalSubmitted ? 1 : 0;
  const total = modules.length + 1;
  const percent = Math.round(((completedModules + finalBonus) / total) * 100);
  progressText.textContent = `${percent}%`;
  progressFill.style.width = `${percent}%`;
  renderResultsOverview();
}

function initializeAnimations() {
  document.body.classList.add("animations-ready");
  if ("IntersectionObserver" in window) {
    revealObserver = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (!entry.isIntersecting) return;
        entry.target.classList.add("is-revealed");
        revealObserver.unobserve(entry.target);
      });
    }, { threshold: 0.12, rootMargin: "0px 0px -8% 0px" });
  }
  prepareAnimations(document);
}

function prepareAnimations(scope = document) {
  if (!document.body.classList.contains("animations-ready")) return;
  if (contentView && scope === contentView) {
    contentView.classList.remove("is-entering");
    void contentView.offsetWidth;
    contentView.classList.add("is-entering");
  }

  const revealSelectors = [
    ".hero-slide",
    ".top-actions",
    ".participant-card",
    ".course-roadmap",
    ".section-band",
    ".info-box",
    ".theory-card",
    ".visual-section",
    ".element-card",
    ".guidance-card",
    ".example-box",
    ".question",
    ".prompt-card",
    ".roadmap-card",
    ".result-panel",
    ".keyfact-card",
    ".dd-item",
    ".timeline-step",
    ".compare-col",
    ".check-item",
    ".glossary-card",
    ".anatomy-row"
  ].join(",");

  scope.querySelectorAll(revealSelectors).forEach((element, index) => {
    if (element.dataset.revealBound) return;
    element.dataset.revealBound = "true";
    element.style.setProperty("--reveal-index", Math.min(index, 8));
    element.classList.add("revealable");
    if (revealObserver) {
      revealObserver.observe(element);
    } else {
      element.classList.add("is-revealed");
    }
  });

  scope.querySelectorAll(".element-card").forEach((card) => {
    if (card.dataset.focusBound) return;
    card.dataset.focusBound = "true";
    card.tabIndex = 0;
    const toggle = () => {
      const container = card.closest(".element-grid") || document;
      container.querySelectorAll(".element-card.is-focused").forEach((item) => {
        if (item !== card) item.classList.remove("is-focused");
      });
      card.classList.toggle("is-focused");
    };
    card.addEventListener("click", toggle);
    card.addEventListener("keydown", (event) => {
      if (event.key === "Enter" || event.key === " ") {
        event.preventDefault();
        toggle();
      }
    });
  });
}

function resetProgress() {
  const confirmed = window.confirm("Сбросить все ответы, открытые ответы и итоговый результат?");
  if (!confirmed) return;
  applyProgress(blankProgress());
  saveState();
  if (isAuthenticated()) {
    renderModule(0);
  } else {
    renderAuthRequired();
  }
  renderParticipantForm();
  updateProgress();
  showToast("Прогресс сброшен.");
}

function escapeHtml(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

function showToast(message) {
  toast.textContent = message;
  toast.classList.add("is-visible");
  clearTimeout(showToast.timer);
  showToast.timer = setTimeout(() => toast.classList.remove("is-visible"), 2200);
}

function copyWithFallback(text) {
  const field = document.createElement("textarea");
  field.value = text;
  field.setAttribute("readonly", "");
  field.style.position = "fixed";
  field.style.left = "-9999px";
  document.body.appendChild(field);
  field.select();
  document.execCommand("copy");
  field.remove();
}
